// v1.2.0 - Enhanced caching and offline support with Workbox
importScripts('https://storage.googleapis.com/workbox-cdn/releases/6.5.4/workbox-sw.js');

if (workbox) {
  // Precache all assets generated by the build process
  workbox.precaching.precacheAndRoute(self.__WB_MANIFEST || []);

  // Cache images with a cache-first strategy
  workbox.routing.registerRoute(
    ({ request }) => request.destination === 'image',
    new workbox.strategies.CacheFirst({
      cacheName: 'creator-armour-images',
      plugins: [
        new workbox.expiration.ExpirationPlugin({
          maxEntries: 100,
          maxAgeSeconds: 30 * 24 * 60 * 60, // 30 days
        }),
        new workbox.cacheableResponse.CacheableResponsePlugin({
          statuses: [0, 200],
        }),
      ],
    })
  );

  // Cache fonts
  workbox.routing.registerRoute(
    ({ request }) => request.destination === 'font',
    new workbox.strategies.CacheFirst({
      cacheName: 'creator-armour-fonts',
      plugins: [
        new workbox.expiration.ExpirationPlugin({
          maxEntries: 10,
          maxAgeSeconds: 365 * 24 * 60 * 60, // 1 year
        }),
      ],
    })
  );

  // Cache API responses with stale-while-revalidate for better offline experience
  // Important: do NOT cache API responses.
  // These are frequently authenticated and must always hit the network; caching can cause
  // stuck logins and "phantom" 404s/401s being served from cache.
  workbox.routing.registerRoute(
    ({ url }) => url.pathname.startsWith('/api/'),
    new workbox.strategies.NetworkOnly()
  );
}

// Enhanced push notifications with better UX
self.addEventListener('push', (event) => {
  let payload = {
    title: 'New Brand Offer',
    body: 'A brand wants to collaborate with you.',
    url: '/creator-dashboard?tab=collabs&subtab=pending',
    icon: '/icon-192x192.png',
    badge: '/icon-192x192.png',
    tag: 'brand-offer',
    requireInteraction: true,
    silent: false,
  };

  try {
    const parsed = event.data?.json();
    if (parsed && typeof parsed === 'object') {
      payload = {
        ...payload,
        ...parsed,
        // Ensure we have proper fallbacks
        title: parsed.title || payload.title,
        body: parsed.body || payload.body,
        url: parsed.url || payload.url,
        tag: parsed.requestId ? `collab-request-${parsed.requestId}` : payload.tag,
      };
    }
  } catch (error) {
    console.warn('Failed to parse push notification data:', error);
  }

  const options = {
    body: payload.body,
    icon: payload.icon,
    badge: payload.badge,
    tag: payload.tag,
    requireInteraction: payload.requireInteraction,
    silent: payload.silent,
    vibrate: [200, 100, 200, 100, 200],
    data: {
      url: payload.url,
      requestId: payload.requestId,
      timestamp: Date.now(),
    },
    actions: [
      {
        action: 'view',
        title: 'View Offer',
        icon: '/icon-192x192.png',
      },
      {
        action: 'dismiss',
        title: 'Later',
      },
    ],
  };

  event.waitUntil(
    self.registration.showNotification(payload.title, options)
  );
});

// Enhanced notification click handling
self.addEventListener('notificationclick', (event) => {
  event.notification.close();

  const action = event.action;
  const targetUrl = event.notification?.data?.url || '/creator-dashboard?tab=collabs&subtab=pending';

  if (action === 'dismiss') {
    return; // Just close the notification
  }

  // Default action or 'view' action
  event.waitUntil(
    clients.matchAll({ type: 'window', includeUncontrolled: true }).then((windowClients) => {
      // Check if there's already a window with the target URL
      for (const client of windowClients) {
        if (client.url === targetUrl && 'focus' in client) {
          return client.focus();
        }
      }

      // If not found, open a new window
      if (clients.openWindow) {
        return clients.openWindow(targetUrl);
      }
    })
  );
});

// Handle service worker updates
self.addEventListener('message', (event) => {
  if (event.data && event.data.type === 'SKIP_WAITING') {
    self.skipWaiting();
  }
});

// Background sync for failed requests (when coming back online)
self.addEventListener('sync', (event) => {
  if (event.tag === 'background-sync') {
    event.waitUntil(syncFailedRequests());
  }
});

async function syncFailedRequests() {
  // Implementation for syncing failed requests when back online
  // This would sync any pending offers or actions that failed due to network issues
  console.log('Background sync triggered - syncing failed requests');
  // TODO: Implement actual sync logic for failed API calls
}

// Handle install and activate events for better caching
self.addEventListener('install', (event) => {
  console.log('Service worker installing...');
  self.skipWaiting(); // Force activation immediately
});

self.addEventListener('activate', (event) => {
  console.log('Service worker activating...');
  // Clean up old caches if needed
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames
          .filter((cacheName) => cacheName.startsWith('creator-armour-'))
          .filter((cacheName) => !['creator-armour-images', 'creator-armour-fonts', 'creator-armour-api'].includes(cacheName))
          .map((cacheName) => caches.delete(cacheName))
      );
    })
  );
});
